+        fs.mkdirSync(path.dirname(filePath), { recursive: true });
+        fs.writeFileSync(filePath, blobBuffer);
+      }
+    } finally {
+      db.close();
+    }
+
+    return TEMP_MODEL_DIR;
+  }
+
+  private static findBundledRvf(modelId: string): string | null {
