+    const candidates = [
+      path.join(dirname, '../../models', `${modelId}.rvf`),
+      path.join(dirname, '../../../dist/models', `${modelId}.rvf`),
+      path.join(dirname, '../../../../dist/models', `${modelId}.rvf`),
+    ];
+
+    for (const candidate of candidates) {
+      if (fs.existsSync(candidate)) return candidate;
+    }
+    return null;
+  }
+}

